var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"잠시만 기다리세요.","JPN":"お待ちください。","ENG":"Please hold.","TWN":"請先等一下。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신은……?","JPN":"あなたは……？","ENG":"You’re...","TWN":"你是……？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……낯이 익군. 뉴스에서 본 적이 있어.","JPN":"……見覚えがある顔だな。ニュースで見たことがあるぞ。","ENG":"I know your face. I saw you on TV.","TWN":"……好面熟喔？我有在新聞上看過你！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"군수회사인 알파트릭스 그룹 전 회장의 손녀 아닌가?","JPN":"軍事企業アルファトリックスグループの前会長の孫娘じゃないか。","ENG":"Aren’t you the granddaughter of the previous President of Alphatrix?","TWN":"你不是軍火公司 阿爾法崔克斯集團前任會長的孫女嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"분명히……. 알파트릭스 이노베이션이라는 카운터 팀의 리더였지.","JPN":"確か……アルファトリックス・イノベーションというカウンターチームのリーダーだったはずだ。","ENG":"You are the leader of the Alphatrix Innovation Counter team, if I remember correctly.","TWN":"我記得……你是制裁者組織 阿爾法崔克斯改革的隊長吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"맞아요. 그리고 이제는 그룹 전체의 회장이기도 하죠.","JPN":"そうです。そして今はグループ全体の会長でもあります。","ENG":"You’re correct. And now I am the President of the entire Alphatrix group.","TWN":"是的，我現在也是集團的現任會長。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"회장이라고?","JPN":"会長だと？","ENG":"You’re the President?","TWN":"你是會長？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"회장직은 공석이었던 것 아니었나? 분명 부회장이 전권 대리를 맡고 있을 텐데?","JPN":"会長の席は空席だったんじゃないのか？\\n確か副会長が全権代理を務めているはずだろう？","ENG":"I thought the President position was vacant. The Vice Chairman was exercising full authority.","TWN":"會長的位置不是空著的嗎？現在不是由副會長全權代理會長的職務嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그간 여러 가지 일이 있었거든요.","JPN":"これまで色々とありまして。","ENG":"Well, many things happened.","TWN":"因為之前發生一些事。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아주 멋지고 친절하신 분의 도움으로 얼마 전 이사회에서 회장으로 선임되었답니다.","JPN":"とても素敵で親切な方の助けで、先日の理事会から会長に選任されました。","ENG":"And with some help from a very nice and kind gentleman, I was elected President by the board of directors.","TWN":"在不久前的董事會中，因為一位非常親切又帥氣的朋友幫忙，讓我得以當上會長。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"외부에는 아직 공표하지 않았지만요.","JPN":"外部にはまだ公表しておりませんが。","ENG":"Though we haven’t officially announced the news yet.","TWN":"但這件事尚未正式對外公開。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……소문으로 듣던 것과는 성격이 좀 다르군.","JPN":"……噂で聞いていたのとはだいぶ性格が違うな。","ENG":"You are very different from the rumors I heard.","TWN":"……你好像跟傳聞中的不太一樣呢？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"소문이 잘못됐던 건지, 아니면 그 여러 가지 일 때문에 바뀐 건지 궁금해지는데.","JPN":"噂が間違っていたのか、\\nそれともその色々なこととやらで人が変わったのか気になるが。","ENG":"I’m curious if the rumor was wrong, or if you had changed.","TWN":"真好奇是傳言有誤，還是因為發生太多事才會變成現在這樣？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"아저씨, 지금 한가하게 이야기나 하고 있을 때야?","JPN":"おじさん、今はのんびりおしゃべりしている場合じゃないよ？","ENG":"Hey, now's not the time for chitchat.","TWN":"大叔，現在應該不是閒聊的時候吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어서 실비아네를 도우러 가야지!","JPN":"早くシルビアたちを助けに行かないと！","ENG":"We have to help Sylvia!","TWN":"要快點去幫希爾維亞啦！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 그쪽이 유미나 씨 맞죠?","JPN":"ああ、あなたがヤナギ・ミナさんですね？","ENG":"Oh, you must be Yoo Mina, right?","TWN":"這位是劉米娜小姐對吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어? 날 알아?","JPN":"え？　私を知っているの？","ENG":"Huh? You know me?","TWN":"嗯？你認識我？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"당연하죠. 그쪽 사장님께 얘기 많이 들었어요.","JPN":"もちろんです。そちらの社長からお話をたくさんお聞きしました。","ENG":"Of course, I heard a lot about you from your Boss.","TWN":"當然，常聽你們老闆提起你。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L31_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 역시, 흐음…….","JPN":"でもやっぱり、ふむふむ……","ENG":"But, hmm...","TWN":"不過，果然是……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐, 뭐야? 왜 갑자기 사람 몸을 위아래로 훑어 보는 건데?","JPN":"な、なに？　なんで急に品定めするような目で見てくるの？","ENG":"W-what the heck? Did you just scan my body?","TWN":"你幹嘛？幹嘛突然這樣打量我？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 나쁘지 않지만 이 정도면 저도 충분히 승산이 있겠네요.","JPN":"はい。悪くはありませんが、\\nこの程度なら私にも十分勝ち目がありそうですね。","ENG":"Well, you’re not bad, but I believe I have a chance.","TWN":"嗯，是還不錯，但這種程度而已，我應該是有贏面的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"승산?","JPN":"勝ち目？","ENG":"A chance?","TWN":"贏面？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"무슨 말인지 몰라도 좀 기분 나쁜데…….","JPN":"どういうことかわからないけど、ちょっと気持ち悪いんだけど……","ENG":"I don’t understand what you’re talking about, but I don’t like it.","TWN":"聽不懂你在說什麼，但感覺很差……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"후훗, 개인적인 일이라서요. 기분이 상하셨다면 사과드릴게요.","JPN":"ふふっ、個人的なことですので。気分を害したのならお詫びします。","ENG":"Haha, it’s something personal. My apologies, if I offended you.","TWN":"呵呵，我是在自言自語，如果讓你覺得不舒服，那我跟你道歉。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"전 유미나 씨와도 가급적이면 친하게 지내고 싶거든요.","JPN":"私はミナさんともなるべく仲良くなりたいんです。","ENG":"I want to be your friend as well, if it’s possible.","TWN":"可以的話，我希望可以和你和平相處。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서 여긴 왜 온 거야?! 이쪽은 지금 바쁘다고!","JPN":"それで、なんでここに来たの！？　こっちは今超忙しいの！","ENG":"So why are you here? We’re busy!","TWN":"所以你來這裡要做什麼？！我們現在很忙好嗎！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"중요한 정보를 전해 드리러 왔어요.","JPN":"重要な情報を伝えに参りました。","ENG":"I have important information for you.","TWN":"我是來帶給你們重要的情報的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저 괴물을 물리칠 방법인데, 한 번 들어 보실래요?","JPN":"あの怪物を阻止できる方法ですが、一度お聞きになりませんか？","ENG":"Regarding how to kill that monster. Are you interested?","TWN":"就是擊敗那個怪物的方法，要聽嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 그게 정말이야?","JPN":"え？　本当に？","ENG":"What? Really?","TWN":"什麼？是真的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 어떻게……? 저 6종 침식체는 우리도 방금 발견한 건데?","JPN":"でもどうやって……？\\nあの第6種侵食体は私たちも今さっき見つけたばかりだけど？","ENG":"But how? This is the first time we’ve ever seen a Category 6 C.O.","TWN":"可是怎麼會……？那個6類侵蝕體是我們剛剛才發現的？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다행히도 이 상황을 미리 예견한 분이 계시거든요.","JPN":"幸いにも、この状況を事前に予測した方がいらっしゃいました。","ENG":"Actually, someone already predicted that something like this would happen.","TWN":"幸好有人早就預料到會發生這個情況。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저 괴물은 여러분께서 예상한 대로 6종 침식체가 확실해요.","JPN":"あの怪物は皆様の想定どおり、第6種侵食体で間違いありません。","ENG":"Like you said, that is a Category 6 Corrupted Object.","TWN":"你們猜的沒錯，那個怪物確實是6類侵蝕體。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저건 그 중에서도 <color=#ffd34c>허신</color>에 속하는 존재…….","JPN":"あれはその中でも<color=#ffd34c>虚神</color>に属する存在……","ENG":"And among the Category 6, that thing belongs to the group called <color=#ffd34c>Hollow Gods</color>...","TWN":"而且屬於<color=#ffd34c>幻神</color>……"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"식별명 <color=#ffd34c>카미마엘</color>입니다.","JPN":"識別名<color=#ffd34c>カミマエル</color>です。","ENG":"Its code name is <color=#ffd34c>Kamimael</color>.","TWN":"又稱為<color=#ffd34c>卡米麥爾</color>。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"허신……?","JPN":"虚神……？","ENG":"Hollow Gods?","TWN":"幻神……？"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"저게 신이라고? 갑자기 왠 종교 이야기야?","JPN":"あれは神なの？　いきなり宗教の話？","ENG":"That’s a god? Are we starting a religion now?","TWN":"那種傢伙也可以稱為神？怎麼突然談起宗教？"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"창조주나 전능신처럼 관념적인 존재를 말하는 건 아니에요.","JPN":"創造主や全能神のような観念的な存在のことではありません。","ENG":"I’m not talking about the conceptual, abstract beings from religion.","TWN":"我說的不是創造主或是全能神，那種客觀認知。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다만…… 우리 우주 밖의 세계에서 만들어져서 법칙과 동떨어진 존재를 말하는 거죠.","JPN":"いわば……私たちが知っている宇宙の外の世界で作られ、\\n法則とかけ離れた存在のことです。","ENG":"They are beings created outside of our space and time, and our universal laws don’t apply to them.","TWN":"他是……在我們宇宙之外的世界，背離法則之下創造出來的。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"법칙과 동떨어져 있다고?","JPN":"法則とかけ離れてる？","ENG":"Our universal laws don’t apply?","TWN":"背離法則？"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 그렇기 때문에 일반적인 방법으로는 죽일 수 없어요.","JPN":"はい。そのため、一般的な方法では殺せません。","ENG":"No, that’s why we can’t kill it with conventional means.","TWN":"沒錯，所以用一般的方法是殺不死他的。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"정확히는 공격을 해 봐야 수면에 비친 달 그림자를 때리는 것과 같죠.","JPN":"正確には、攻撃をしても水面に映った月影を叩くようなものです。","ENG":"Attacking it would be like hitting the moon reflected on the surface of water.","TWN":"意思就是，必須攻擊才能打中倒映在水面的月影。"},"stage":{"bg":"MAINSTREAM_808","bgm":"THEMA_ALPHATRIX","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 얘기……. 어디서 들었던 것 같군.","JPN":"その話……どこかで聞いたような気がするな。","ENG":"Hey, that sounds familiar...","TWN":"那句話……我怎麼好像在哪聽過？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"맞아요. 리플레이서가 사용했던 불멸체 코어는 바로 저들을 모방해서 만들어진 열화품이에요.","JPN":"そうです。リプレイサーが使用していた不滅体コアは、\\nまさに彼らを模して作られた劣化品です。","ENG":"Yes. The Immortal System Core that the Replacers used was an inferior copy of the Hollow Gods.","TWN":"沒錯，克隆集團使用過的不滅者核心，就是模仿他們的劣質品。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"물론 성능적으로는 비교할 수 없죠. 허신의 에너지원은 무한한 데다가, 코어를 파괴하는 것도 불가능하니까요.","JPN":"もちろん性能的には比べ物になりません。\\n虚神のエネルギー源は無限な上、コアを破壊することも不可能ですから。","ENG":"Obviously the Hollow Gods are far superior in terms of functionality. They have infinite energy, and it’s virtually impossible to destroy their core.","TWN":"性能上當然是無法比的，幻神的能源是無限的，核心也無法破壞。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"불멸체 코어는 1급 기밀사항이야. 네가 그걸 어떻게 알고 있는 거야?","JPN":"不滅体コアは第1級機密事項よ。アンタはそれをどうして知ってるの？","ENG":"The Immortal System Core is top secret. Where did you learn about it?","TWN":"不滅者核心是1級機密，你怎麼會知道？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아주 멋지고 친절하신 분께서 가르쳐 주셨어요.","JPN":"とても素敵で親切な方に教えていただきました。","ENG":"A very nice and kind gentleman taught me.","TWN":"是一位非常親切又帥氣的朋友告訴我的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그리고 제가 어디서 그 얘기를 들었는지는 여러분에게 중요한 문제가 아니에요.","JPN":"そして、私がどこでその話を聞いたのかは、\\n今の皆様にとって重要な問題ではありません。","ENG":"Where I got the intel is not the issue here.","TWN":"再說，我是從哪聽說這些事的，對你們來說應該不重要吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"지금 중요한 건 허신을 죽이는 방법이죠.","JPN":"今重要なのは虚神を倒せる方法です。","ENG":"What’s important is how to kill that Hollow God.","TWN":"現在的重點是要怎麼殺死幻神。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"말씀드린 대로 수면에 비친 달 그림자를 파괴하려면 두 가지 방법이 있어요.","JPN":"申し上げたとおり、\\n水面に映った月影を破壊するには2つの方法があります。","ENG":"So, there are two methods to destroy the moon's reflection on the water's surface.","TWN":"就如同我剛才所說，要破壞倒映在水面上的月影，有兩種方法。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"강력한 화력으로 호수를 통째로 증발시켜 버리거나…….","JPN":"強力な力で湖を丸ごと蒸発させるか……","ENG":"You either evaporate the entire body of water with strong firepower...","TWN":"第一種是用強大的火力使湖水整個蒸發……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이쪽도 극히 불합리한 수단을 동원해서 하늘에 뜬 달 자체를 찔러 죽여야죠.","JPN":"こちらも極めて不合理な手段で、空に浮かんだ月そのものを殺さなければなりません。","ENG":"Or use some very illogical means and stab the moon in the sky.","TWN":"第二種就是你們要使用非常不合理的方法，刺死高掛在空中的月亮。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"첫 번째 방법은 무슨 뜻인지 대충 알겠어.","JPN":"最初の方法はどんな意味なのか大体わかったわ。","ENG":"I understood the first part.","TWN":"第一種方法我大概明白什麼意思。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 두 번째는 이해가 안 가. 그 불합리한 수단이란 게 대체 뭔데?","JPN":"でも2つ目の方法は理解できない。その不合理な手段ってつまりどういうこと？","ENG":"But the second one, I don’t get it. What do you mean by illogical?","TWN":"但第二種就不太理解，所謂不合理的方法是指什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"바로 유미나 씨, 당신이 가지고 있는 신을 베는 검.","JPN":"それはヤナギ・ミナさん、あなたが持っている神を斬る剣。","ENG":"Your sword can cut down gods.","TWN":"就是劉米娜小姐，你手上那把砍神的劍。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"테크 레벨 언노운 아티팩트, <color=#ffd34c>울브즈베인</color>이에요.","JPN":"テックレベル・アンノウンのアーティファクト、<color=#ffd34c>ウルブズベイン</color>です。","ENG":"Tech Level Unknown Artifact, <color=#ffd34c>Wolvesbane</color>.","TWN":"也就是技術等級未知的人造神器 <color=#ffd34c>狼之災禍</color>。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이 검으로…… 저걸 죽일 수 있다고?","JPN":"この剣で……あれを殺せるの？","ENG":"I can kill that thing... with my sword?","TWN":"你說……這把劍可以殺死他？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이미 미나 씨도 어렴풋이 깨달았을 거예요. 울브즈베인의 힘을.","JPN":"すでにミナさんも気づきつつあるでしょう。ウルブズベインの力を。","ENG":"You must have felt it the power that Wolvesbane holds by now.","TWN":"你應該也有隱約感覺到狼之災禍的能力吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 검을 심장에 찔러 넣으면, 설령 신의 혼이라고 해도 죽일 수 있어요.","JPN":"その剣を心臓に突き刺せば、たとえ神の魂であれど破壊することが可能です。","ENG":"Stab the heart with your sword, and you’ll be able to kill a god.","TWN":"只要將那把劍刺向心臟，就算是神的靈魂也能夠殺死。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어때요? 참 쉽죠?","JPN":"どうですか？　本当に簡単でしょう？","ENG":"Easy, isn't it?","TWN":"OK嗎？很簡單對吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 갑자기 나타나서 그런 뜬금없는 소릴 해도…….","JPN":"いや、いきなり現れてそんな突拍子もないことを言われても……","ENG":"Everything you say is so random, coming out of nowhere...","TWN":"你突然出現沒頭沒尾地跟我們說這些……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇다고 다른 방법을 찾을 만큼 시간이 넉넉하진 않잖아요?","JPN":"とはいえ、他の手段を探す時間があるとは言えない状況でしょう？","ENG":"Yet you don’t have the time to find another way, do you?","TWN":"你們也沒時間再想其他方法吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"미나 씨의 선배라는 분도, 지금 이 자리에 안 계신 걸 보면요.","JPN":"ミナさんの先輩という方も、今この場にいらっしゃらないですし。","ENG":"I see that your senior is not here at the moment.","TWN":"更何況，那位劉米娜小姐的前輩，不是還下落不明中嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"Well...","TWN":"那個……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"알겠어. 네 말대로 해 볼게.","JPN":"わかった。あなたの言うとおりにしてみる。","ENG":"Okay, I'll give it a try.","TWN":"好吧！就照你說的做！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"잠깐, 저런 허무맹랑한 말을 믿겠다고?","JPN":"ちょっと待って、あんなデタラメな話を信じるの？","ENG":"Wait, you believe that absurd story?","TWN":"等一下，你相信那種鬼話嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금은 한 명이 아쉬운 상황이야. 그러다 실패라도 했다간…….","JPN":"今は一人一人が大事な状況よ。そんなことをして失敗でもしたら……","ENG":"We need as many people as possible. If you fail...","TWN":"現在每一個人力都非常重要，萬一你失敗的話……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"난 어떻게든 저 괴물을 막고 선배를 찾아야 해.","JPN":"私は何としてもあの化け物を止めて、先輩を探さないといけない。","ENG":"I have to stop the monster and find Shiyoon.","TWN":"無論如何，我一定要阻止那個怪物找到前輩！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"실낱 같은 방법이라도 있다면…… 거기에 목숨을 걸어 보겠어.","JPN":"少しでも希望があるなら……そこに命だってかけてみせる。","ENG":"If there is a possibility... I’m willing to risk my life for it.","TWN":"只要有一絲希望……我都會賭上我的性命去嘗試！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"자, 잠시만요. 저도 같이 가겠어요.","JPN":"ま、待ってください。私も一緒に行きます。","ENG":"W-wait, I’m coming with you.","TWN":"等…等等，我也一起去。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응? 그래도 괜찮겠어?","JPN":"本当に？　いいの？","ENG":"Huh? Are you sure?","TWN":"嗯？這樣沒關係嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"네. 중장님을 돕기로 했으니까요.","JPN":"はい。中将の力になるって決めましたから。","ENG":"Yes, I promised to help the Lieutenant General.","TWN":"嗯，因為我已經決定要幫助中將。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"힘이 닿는 한……. 저는 그 여자와 다르다는 걸 꼭 증명해 보이겠어요.","JPN":"力の及ぶ限り……私はあの女と違うということを、必ず証明してみせます。","ENG":"I will help as much as I can... so that I can prove that I’m different from that woman.","TWN":"在我能力所及的範圍內……我一定要證明我和她是不同的。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아. 그렇다면 나도 같이 내려간다.","JPN":"よし。なら俺も一緒に行くぞ。","ENG":"Okay, then I’m coming with you, too.","TWN":"很好，那也算上我吧！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"일반인 용병이라지만 뭐라도 도울 수 있겠지.","JPN":"一般人の傭兵でも何かしら役に立つだろう。","ENG":"I’m just a non-Counter mercenary, but there must be something I can do.","TWN":"雖然我只是區區一介傭兵，但應該還是派得上用場吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 당신은 여기 남아 주세요.","JPN":"いいえ。あなたはここに残ってください。","ENG":"No, you should stay here.","TWN":"不，你待在這裡就好。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……어째서지?","JPN":"……なぜだ？","ENG":"Why?","TWN":"……為什麼？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아직 당신이 해 줘야 할 일이 있거든요.","JPN":"あなたにはやって貰わなければならないことがあります。","ENG":"There’s something you have to do.","TWN":"你還有其他事要辦。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"일행 분들과 같이 노바급 리액터를 찾으러 갔다고 들었는데, 맞나요?","JPN":"お連れ様と一緒にノヴァ級リアクターを探しに行ったと聞きましたが、\\n本当ですか？","ENG":"I heard you and others went to find the Nova-Class Reactor, am I correct?","TWN":"我聽說你們是去找諾瓦反應爐對吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 일이라면 아쉽게 됐지.","JPN":"そのことなら残念な結果だった。","ENG":"Yeah, too bad it didn’t go right.","TWN":"你是說那件事喔？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그건 이제 모든 에너지를 소모하고 껍데기만 남은 고철일 뿐이야.","JPN":"あれはもうすべてのエネルギーを使い果たし、\\n空になったクズ鉄に過ぎない。","ENG":"All we have left is an empty shell without any energy.","TWN":"非常遺憾，它的能源已經全部耗盡，只剩下空殼而已。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"껍데기라고요?","JPN":"空になった、ですか？","ENG":"An empty shell?","TWN":"空殼嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그거면 충분해요.","JPN":"それで十分です。","ENG":"That’s good enough.","TWN":"只剩空殼也可以。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ALPHATRIX","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};